INSERT INTO devices (id, mac, ip, hostname, manufacturer, category, room, connection, ip_type, known, online, description) VALUES (gen_random_uuid(), '00:11:22:33:44:01', '192.168.0.10', 'gateway-placeholder', 'Example Corp', 'Infrastructure', 'Office', 'Wired', 'S', TRUE, true, 'Example row — replace with your gateway or NAS.') ON CONFLICT (mac) DO UPDATE SET ip = COALESCE(EXCLUDED.ip, devices.ip), hostname = COALESCE(EXCLUDED.hostname, devices.hostname), manufacturer = COALESCE(EXCLUDED.manufacturer, devices.manufacturer), category = COALESCE(EXCLUDED.category, devices.category), room = COALESCE(EXCLUDED.room, devices.room), connection = EXCLUDED.connection, ip_type = EXCLUDED.ip_type, known = TRUE, online = EXCLUDED.online, description = COALESCE(EXCLUDED.description, devices.description);
